(function(m) {
  var connections = [];
  var activeConnectionId = null;
  var menuOpen = false;
  var randomMode = false;
  var selectedForRandom = [];
  var STORAGE_KEY = 'qcs-random-profiles';
  var RANDOM_MODE_KEY = 'qcs-random-mode';

  try {
    var saved = localStorage.getItem(STORAGE_KEY);
    if (saved) selectedForRandom = JSON.parse(saved);
    if (localStorage.getItem(RANDOM_MODE_KEY) === 'true') randomMode = true;
  } catch(e) {}

  function saveRandomState() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(selectedForRandom));
      localStorage.setItem(RANDOM_MODE_KEY, String(randomMode));
    } catch(e) {}
  }

  async function fetchConnections() {
    try {
      var data = await m.apiFetch('/connections');
      if (Array.isArray(data)) {
        connections = data.sort(function(a, b) { return (a.name || '').localeCompare(b.name || ''); });
      }
      return connections;
    } catch(e) {
      console.error('[QCS] Failed to fetch connections:', e);
      return [];
    }
  }

  function getActiveChatId() {
    try {
      return localStorage.getItem('marinara-active-chat-id') || null;
    } catch(e) { return null; }
  }

  async function getActiveConnectionId() {
    var chatId = getActiveChatId();
    if (!chatId) return null;
    try {
      var chat = await m.apiFetch('/chats/' + chatId);
      return chat.connectionId || null;
    } catch(e) { return null; }
  }

  async function switchConnection(connId) {
    var chatId = getActiveChatId();
    if (!chatId) return;
    try {
      await m.apiFetch('/chats/' + chatId, {
        method: 'PATCH',
        body: JSON.stringify({ connectionId: connId })
      });
      activeConnectionId = connId;

      // Force React Query to refetch chat data by dispatching a focus event
      // React Query refetches stale queries on window focus by default
      window.dispatchEvent(new Event('focus'));

      // Also try triggering via visibilitychange
      try {
        Object.defineProperty(document, 'hidden', { value: false, configurable: true });
        document.dispatchEvent(new Event('visibilitychange'));
      } catch(e) {}

      // Also invalidate by re-navigating to the same chat
      // This forces the app to reload chat details
      var currentId = localStorage.getItem('marinara-active-chat-id');
      if (currentId) {
        localStorage.removeItem('marinara-active-chat-id');
        requestAnimationFrame(function() {
          localStorage.setItem('marinara-active-chat-id', currentId);
          // Trigger storage event for any listeners
          window.dispatchEvent(new StorageEvent('storage', {
            key: 'marinara-active-chat-id',
            newValue: currentId
          }));
        });
      }

      renderList();
    } catch(e) {
      console.error('[QCS] Failed to switch connection:', e);
    }
  }

  function renderList() {
    var body = document.getElementById('qcs-menu-body');
    if (!body) return;
    body.innerHTML = '';

    if (connections.length === 0) {
      body.innerHTML = '<div class="qcs-loading">No connections found.</div>';
      return;
    }

    connections.forEach(function(conn) {
      var isActive = conn.id === activeConnectionId;
      var item = document.createElement('div');
      item.className = 'qcs-item' + (isActive ? ' active' : '');

      var nameSpan = document.createElement('span');
      nameSpan.textContent = conn.name || conn.id;
      item.appendChild(nameSpan);

      if (randomMode) {
        var checkbox = document.createElement('span');
        var isChecked = selectedForRandom.indexOf(conn.id) !== -1;
        checkbox.textContent = isChecked ? '☑' : '☐';
        checkbox.style.cssText = 'margin-left:auto;cursor:pointer;font-size:0.875rem;color:' + (isChecked ? 'var(--primary)' : 'var(--muted-foreground)');
        checkbox.addEventListener('click', function(e) {
          e.stopPropagation();
          var idx = selectedForRandom.indexOf(conn.id);
          if (idx !== -1) {
            selectedForRandom.splice(idx, 1);
          } else {
            selectedForRandom.push(conn.id);
          }
          saveRandomState();
          renderList();
        });
        item.appendChild(checkbox);
      } else {
        var check = document.createElement('span');
        check.className = 'qcs-check';
        check.textContent = '✓';
        item.appendChild(check);
      }

      item.addEventListener('click', function() {
        switchConnection(conn.id);
      });

      body.appendChild(item);
    });
  }

  async function triggerRandom() {
    if (selectedForRandom.length === 0) return;
    var candidates = selectedForRandom.slice();
    if (candidates.length > 1) {
      var idx = candidates.indexOf(activeConnectionId);
      if (idx !== -1) candidates.splice(idx, 1);
    }
    var chosen = candidates[Math.floor(Math.random() * candidates.length)];
    await switchConnection(chosen);
  }

  function waitForElement(selector, cb) {
    var el = document.querySelector(selector);
    if (el) { cb(el); return; }
    m.observe(document.body, function(mutations, observer) {
      var el = document.querySelector(selector);
      if (el) {
        observer.disconnect();
        cb(el);
      }
    }, { childList: true, subtree: true });
  }

  function init() {
    waitForElement('form, [class*="input"], [class*="send"], textarea', function() {
      m.setTimeout(function() { buildUI(); }, 500);
    });
  }

  async function buildUI() {
    await fetchConnections();
    activeConnectionId = await getActiveConnectionId();

    var anchor = findAnchor();
    if (!anchor) {
      console.warn('[QCS] Could not find send area. Retrying...');
      m.setTimeout(function() { buildUI(); }, 2000);
      return;
    }

    var wrapper = anchor.parentElement;
    if (!wrapper) return;
    wrapper.style.position = 'relative';

    var chevron = document.createElement('div');
    chevron.id = 'qcs-chevron-btn';
    chevron.title = 'Quick Connection Switcher';
    chevron.innerHTML = '<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="18 15 12 9 6 15"></polyline></svg>';

    var menu = document.createElement('div');
    menu.id = 'qcs-menu';
    menu.innerHTML = '<div id="qcs-menu-header"><span>Connections</span><button id="qcs-random-btn" title="Toggle Random Mode">🎲</button></div><div id="qcs-menu-body"><div class="qcs-loading">Loading...</div></div>';

    wrapper.insertBefore(chevron, anchor);
    wrapper.appendChild(menu);

    var randomBtn = document.getElementById('qcs-random-btn');
    if (randomMode && randomBtn) randomBtn.classList.add('active');

    chevron.addEventListener('click', async function(e) {
      e.stopPropagation();
      menuOpen = !menuOpen;
      if (menuOpen) {
        chevron.classList.add('active');
        menu.classList.add('show');
        await fetchConnections();
        activeConnectionId = await getActiveConnectionId();
        renderList();
      } else {
        chevron.classList.remove('active');
        menu.classList.remove('show');
      }
    });

    if (randomBtn) {
      randomBtn.addEventListener('click', function(e) {
        e.stopPropagation();
        randomMode = !randomMode;
        if (randomMode) {
          randomBtn.classList.add('active');
        } else {
          randomBtn.classList.remove('active');
        }
        saveRandomState();
        renderList();
      });
    }

    m.on(document, 'click', function(e) {
      if (!menu.contains(e.target) && e.target !== chevron && !chevron.contains(e.target)) {
        menuOpen = false;
        chevron.classList.remove('active');
        menu.classList.remove('show');
      }
    });

    menu.addEventListener('click', function(e) { e.stopPropagation(); });

    renderList();
  }

  function findAnchor() {
    var buttons = document.querySelectorAll('button');
    for (var i = 0; i < buttons.length; i++) {
      var btn = buttons[i];
      var svg = btn.querySelector('svg');
      if (!svg) continue;
      var path = svg.querySelector('path, line, polyline');
      if (!path) continue;
      var parent = btn.closest('form') || btn.parentElement;
      var textarea = parent ? parent.querySelector('textarea') : null;
      if (textarea) return btn;
    }
    var textareas = document.querySelectorAll('textarea');
    for (var j = 0; j < textareas.length; j++) {
      var ta = textareas[j];
      var container = ta.closest('form') || ta.parentElement;
      if (container) {
        var sendBtn = container.querySelector('button:last-of-type');
        if (sendBtn) return sendBtn;
      }
    }
    return null;
  }

  init();
})(marinara);
